# -*- coding: utf-8 -*-
"""Генерация s22–s32 (§22–§32) для банка Мединского, 5 кл."""
import json
from pathlib import Path

OUT = Path(__file__).parent
TB = "Мединский В.Р. и др. История Древнего мира. 5 класс"
SRC = "Мединский, История Древнего мира, 5 кл."


def tags(
    qt,
    th,
    concepts=(),
    entities=(),
    processes=(),
    periods=(),
    skills=(),
    geography=(),
    dtag="easy",
):
    return {
        "entities": list(entities),
        "concepts": list(concepts),
        "processes": list(processes),
        "periods": list(periods),
        "skills": list(skills),
        "geography": list(geography),
        "difficulty": dtag,
        "question_type": qt,
        "grade": [5],
        "source": SRC,
        "themes": list(th),
    }


def df(p, s):
    return {"primary": p, "secondary": s}


def dump(fn, section, rows):
    obj = {"meta": {"textbook": TB, "section": section}, "questions": rows}
    txt = json.dumps(obj, ensure_ascii=False, indent=2)
    (OUT / fn).write_text(txt + "\n", encoding="utf-8")
    json.loads(txt)


def sc(b, n, q, opts, ok_i, ex, pg, par, pri, sec, th, **kw):
    o = list(opts)
    dtag = f"{pri}+{sec}" if pri != sec else pri
    return {
        "id": f"{b}-{n:03d}",
        "type": "single_choice",
        "question": q,
        "options": o,
        "correct_answers": [o[ok_i]],
        "explanation": ex,
        "source": {"paragraph": par, "page": pg},
        "difficulty": df(pri, sec),
        "tags": tags("single_choice", th, dtag=dtag, **kw),
    }


def mc(b, n, q, opts, ok_idx, ex, pg, par, pri, sec, th, **kw):
    o = list(opts)
    dtag = f"{pri}+{sec}" if pri != sec else pri
    extra_sk = kw.pop("skills", [])
    skills = ["множественный выбор"] + [s for s in extra_sk if s != "множественный выбор"]
    return {
        "id": f"{b}-{n:03d}",
        "type": "multiple_choice",
        "question": q,
        "options": o,
        "correct_answers": [o[i] for i in ok_idx],
        "explanation": ex,
        "source": {"paragraph": par, "page": pg},
        "difficulty": df(pri, sec),
        "tags": tags("multiple_choice", th, dtag=dtag, skills=skills, **kw),
    }


def op(b, n, q, ca, aa, kwlist, ex, pg, par, pri, sec, th, **t_kw):
    dtag = f"{pri}+{sec}" if pri != sec else pri
    extra_sk = t_kw.pop("skills", [])
    skills = ["объяснение"] + [s for s in extra_sk if s != "объяснение"]
    return {
        "id": f"{b}-{n:03d}",
        "type": "open",
        "question": q,
        "correct_answer": ca,
        "acceptable_answers": aa,
        "keywords": kwlist,
        "explanation": ex,
        "source": {"paragraph": par, "page": pg},
        "difficulty": df(pri, sec),
        "tags": tags("open", th, dtag=dtag, skills=skills, **t_kw),
    }


def ma(b, n, q, L, R, pairs, ex, pg, par, pri, sec, th, **kw):
    dtag = f"{pri}+{sec}" if pri != sec else pri
    li = [{"id": f"L{i+1}", "text": t} for i, t in enumerate(L)]
    ri = [{"id": f"R{i+1}", "text": t} for i, t in enumerate(R)]
    cp = [{"left": f"L{a}", "right": f"R{b}"} for a, b in pairs]
    extra_sk = kw.pop("skills", [])
    skills = ["сопоставление"] + [s for s in extra_sk if s != "сопоставление"]
    return {
        "id": f"{b}-{n:03d}",
        "type": "matching",
        "question": q,
        "left_items": li,
        "right_items": ri,
        "correct_pairs": cp,
        "explanation": ex,
        "source": {"paragraph": par, "page": pg},
        "difficulty": df(pri, sec),
        "tags": tags("matching", th, dtag=dtag, skills=skills, **kw),
    }


def ch(b, n, q, items, order, ex, pg, par, pri, sec, th, **kw):
    dtag = f"{pri}+{sec}" if pri != sec else pri
    ord_i = [items[i] for i in order]
    extra_sk = kw.pop("skills", [])
    skills = ["хронологический порядок"] + [s for s in extra_sk if s != "хронологический порядок"]
    return {
        "id": f"{b}-{n:03d}",
        "type": "chronology",
        "question": q,
        "items": list(items),
        "correct_order": order,
        "correct_answers": ord_i,
        "explanation": ex,
        "source": {"paragraph": par, "page": pg},
        "difficulty": df(pri, sec),
        "tags": tags("chronology", th, dtag=dtag, skills=skills, **kw),
    }


