def main():
    jobs = [
        ("s22.json", S22, q22),
        ("s23.json", S23, q23),
        ("s24.json", S24, q24),
        ("s25.json", S25, q25),
        ("s26.json", S26, q26),
        ("s27.json", S27, q27),
        ("s28.json", S28, q28),
        ("s29.json", S29, q29),
        ("s30.json", S30, q30),
        ("s31.json", S31, q31),
        ("s32.json", S32, q32),
    ]
    for fn, section, builder in jobs:
        rows = builder()
        assert len(rows) == 20, (fn, len(rows))
        types = {r["type"] for r in rows}
        assert "open" in types and "matching" in types and "chronology" in types and "multiple_choice" in types, fn
        dump(fn, section, rows)
    print("OK: 11 файлов, валидация пройдена.")


if __name__ == "__main__":
    main()
